CREATE TABLE notifications (notification_id UUID PRIMARY KEY DEFAULT gen_random_uuid(), recipient_id UUID NOT NULL REFERENCES users(user_id) ON DELETE CASCADE, recipient_type user_role NOT NULL, channels TEXT[] NOT NULL, title VARCHAR(255) NOT NULL, body TEXT NOT NULL, status VARCHAR(40) NOT NULL DEFAULT 'queued', is_read BOOLEAN NOT NULL DEFAULT FALSE, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW()) PARTITION BY RANGE (created_at);
CREATE TABLE notifications_default PARTITION OF notifications DEFAULT;
CREATE TABLE notification_delivery_logs (log_id UUID PRIMARY KEY DEFAULT gen_random_uuid(), notification_id UUID NOT NULL REFERENCES notifications(notification_id) ON DELETE CASCADE, channel VARCHAR(10) NOT NULL, provider VARCHAR(50), status VARCHAR(40) NOT NULL, sent_at TIMESTAMPTZ, delivered_at TIMESTAMPTZ);
